import sys
from collections import deque

class Solution:
    def isCyclic(self, edges: list[list[int]], V: int) -> bool:
        graph = [[] for _ in range(V)]
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)
        visited = [False] * V
        for i in range(V):
            if not visited[i]:
                if self._isCyclicUtil(graph, visited, i, -1):
                    return True
        return False

    def _isCyclicUtil(self, graph, visited, v, parent):
        visited[v] = True
        for neighbor in graph[v]:
            if not visited[neighbor]:
                if self._isCyclicUtil(graph, visited, neighbor, v):
                    return True
            elif neighbor != parent:
                return True
        return False

if __name__ == '__main__':
