#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isCyclic(vector<vector<int>>& edges, int V) {
        vector<vector<int>> graph(V);
        for (const auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            graph[edge[1]].push_back(edge[0]);
        }
        vector<bool> visited(V, false);
        for (int i = 0; i < V; ++i) {
            if (!visited[i] && _isCyclicUtil(graph, visited, i, -1)) {
                return true;
            }
        }
        return false;
    }

private:
    bool _isCyclicUtil(const vector<vector<int>>& graph, vector<bool>& visited, int v, int parent) {
        visited[v] = true;
        for (int neighbor : graph[v]) {
            if (!visited[neighbor]) {
                if (_isCyclicUtil(graph, visited, neighbor, v)) {
                    return true;
                }
            } else if (neighbor != parent) {
                return true;
            }
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (int i = 0; i < E; ++i) {
        if (!(cin >> edges[i][0] >> edges[i][1])) return 0;
    }
    Solution sol;
    cout << (sol.isCyclic(edges, V) ? "true" : "false") << "\n";
    return 0;
}
